module top_module(datain, dataout, clk, clr, WE);input [31:0] datain;
    output [31:0] dataout;
    input clk, clr, WE;

    reg [31:0] invalid_reg;

always @(posedge clk or posedge clr)
begin
  if(clr)
    invalid_reg = 0;  
  else
    if(WE == 1)
    invalid_reg =  datain;
end    
  assign dataout = invalid_reg;

endmodule
